export const getTemplateIdFromPathway = (pathwayId: string): string | null => {
  const pathway = BUSINESS_PATHWAYS.find((p) => p.id === pathwayId);
  return pathway ? pathway.id : null;
};

export type PathwayId = (typeof BUSINESS_PATHWAYS)[number]['id'];